<script>
(function(){
function g(id){return document.getElementById(id)}
function e(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;')}
function br(s){return e(s).replace(/\n/g,'<br>')}

function parseSent(raw){
  raw=String(raw||'').replace(/\r/g,'').replace(/<\/?USERPHONE[^>]*>/gi,'').trim();
  var all=raw.split('\n');
  var isSep=function(l){return /^[─━\-—_]{5,}$/.test(l.trim())};
  var date='',time='';
  for(var i=all.length-1;i>=0;i--){
    var m=all[i].trim().match(/^(?:(.*?)\s{2,})?(\d{1,2}:\d{2})$/);
    if(m){date=(m[1]||'').trim();time=m[2];all.splice(i,1);break}
  }
  var header=(all[0]||'').trim(),type='',title='',hm;
  if((hm=header.match(/^\[\s*Chat:\s*(.*?)\s*\]$/i))){type='chat';title=hm[1]}
  else if(/^\[\s*Social Actions\s*\]$/i.test(header)){type='social';title='Social'}
  else if(/^\[\s*Order Placed\s*\]$/i.test(header)){type='shop';title='Order Placed'}
  else if(/^\[\s*Bank Transfer\s*\]$/i.test(header)){type='bank';title='Bank Transfer'}
  else if((hm=header.match(/^\[\s*Contact Added:\s*(.*?)\s*\]$/i))){type='contact';title=hm[1]}
  else{type='unknown';title=header}
  var items=[],extra=[];
  for(var j=1;j<all.length;j++){
    var line=all[j];if(isSep(line)||!line.trim())continue;
    var nm=line.match(/^(\d+)\.\s+([\s\S]*)$/);
    if(nm){items.push(nm[2].trim())}
    else if(/^Total/i.test(line.trim())){extra.push(line.trim())}
    else if(items.length){items[items.length-1]+='\n'+line.trim()}
  }
  return {type:type,title:title,date:date,time:time,items:items,extra:extra,header:header};
}

var THEME={
  chat:   {c:'#34c759',ic:'💬',app:'Messages'},
  social: {c:'#ff6b9d',ic:'📱',app:'Social'},
  shop:   {c:'#f5a623',ic:'🛍️',app:'Shop'},
  bank:   {c:'#30d158',ic:'🏦',app:'Bank'},
  contact:{c:'#0a84ff',ic:'👤',app:'Contacts'},
  unknown:{c:'#0a84ff',ic:'📱',app:'Phone'}
};

function clock(P){return P.time?'<span class="upu-clk">'+e(P.time)+'</span>':''}
function tstamp(P){return P.time?'<div class="upu-ts">'+e(P.time)+'</div>':''}

function renderChat(P){
  var group=/\(Group\)/i.test(P.title),name=P.title.replace(/\s*\(Group\)\s*$/i,'');
  var h='<div class="upu-bubs">';
  if(!P.items.length)h+='<div class="upu-empty">No messages</div>';
  P.items.forEach(function(t){h+='<div class="upu-bub">'+br(t)+tstamp(P)+'</div>'});
  h+='</div>';
  return {sub:(group?'Group · ':'To ')+e(name),body:h};
}
function renderSocial(P){
  var h='<div class="upu-acts">';
  P.items.forEach(function(t){
    var mm=t.match(/^\[([^\]]+)\]\s*([\s\S]*)$/);
    var tag=mm?mm[1].trim():'',rest=mm?mm[2].trim():t,head=(tag.split(/\s+/)[0]||'').toUpperCase();
    var ic='📌',lbl=tag,cls='';
    if(head==='LIKE'&&/COMMENT/i.test(tag)){ic='❤️';lbl='Liked a comment'}
    else if(head==='LIKE'){ic='❤️';lbl='Liked a post'}
    else if(head==='COMMENT'){ic='💬';lbl='Commented'}
    else if(head==='REPLY'){ic='↩️';var rt=tag.match(/REPLY to (.*?) on/i);lbl='Replied'+(rt?' to '+rt[1]:'')}
    else if(head==='NEW'){ic='✍️';lbl='New post';cls=' upu-act-post'}
    else if(head==='SHARE'){ic='🔁';lbl='Shared a post'}
    var quote='';var q=tag.match(/[—-]\s*"([\s\S]*?)"/);if(q)quote='<div class="upu-quote">'+br(q[1])+'</div>';
    h+='<div class="upu-act'+cls+'"><span class="upu-act-ic">'+ic+'</span><div class="upu-act-b"><div class="upu-act-l">'+e(lbl)+'</div>'+(rest?'<div class="upu-act-t">'+br(rest)+'</div>':'')+quote+'</div></div>';
  });
  h+='</div>';
  return {sub:P.items.length+' action'+(P.items.length!==1?'s':''),body:h};
}
function renderShop(P){
  var h='<div class="upu-rows">';
  P.items.forEach(function(t){
    var mm=t.match(/^([\s\S]*?)\s*[×x]\s*(\d+)\s*@\s*([\s\S]*)$/);
    if(mm)h+='<div class="upu-row"><div class="upu-row-nm">'+e(mm[1].trim())+'</div><div class="upu-row-meta">×'+e(mm[2])+' · '+e(mm[3].trim())+'</div></div>';
    else h+='<div class="upu-row"><div class="upu-row-nm">'+br(t)+'</div></div>';
  });
  h+='</div>';
  var tot='';P.extra.forEach(function(x){tot+='<div class="upu-total">'+e(x)+'</div>'});
  return {sub:P.items.length+' item'+(P.items.length!==1?'s':''),body:h+tot,accentTotal:true};
}
function renderBank(P){
  var h='<div class="upu-rows">';
  P.items.forEach(function(t){
    var mm=t.match(/^To:\s*([\s\S]*?)\s{2,}Amount:\s*([\s\S]*?)(?:\s*\(([\s\S]*)\))?$/);
    if(mm){
      h+='<div class="upu-xfer"><div class="upu-xfer-ic">↗</div><div class="upu-xfer-b"><div class="upu-xfer-to">'+e(mm[1].trim())+'</div>'+(mm[3]?'<div class="upu-xfer-note">'+br(mm[3].trim())+'</div>':'')+'</div><div class="upu-xfer-amt">'+e(mm[2].trim())+'</div></div>';
    } else h+='<div class="upu-row"><div class="upu-row-nm">'+br(t)+'</div></div>';
  });
  h+='</div>';
  var tot='';P.extra.forEach(function(x){tot+='<div class="upu-total">'+e(x)+'</div>'});
  return {sub:'Transfer',body:h+tot};
}
function renderContact(P){
  return {sub:'Added to contacts',body:'<div class="upu-contact"><span class="upu-act-ic">👤</span><div class="upu-act-l">'+e(P.title)+'</div></div>'};
}

function render(){
  var host=g('upu-view');if(!host)return;
  var raw='';try{var el=g('upu-d');if(el)raw=(el.textContent||'')}catch(_){}
  var P=parseSent(raw);
  var th=THEME[P.type]||THEME.unknown;
  var rr;
  if(P.type==='chat')rr=renderChat(P);
  else if(P.type==='social')rr=renderSocial(P);
  else if(P.type==='shop')rr=renderShop(P);
  else if(P.type==='bank')rr=renderBank(P);
  else if(P.type==='contact')rr=renderContact(P);
  else rr={sub:'',body:'<div class="upu-empty">'+br(raw)+'</div>'};
  var html='<div class="upu-wrap"><div class="upu-card" style="--ac:'+th.c+'">'
    +'<div class="upu-bar"><span class="upu-app"><span class="upu-appic" style="background:'+th.c+'">'+th.ic+'</span>'+e(th.app)+'</span>'+clock(P)+'</div>'
    +(rr.sub?'<div class="upu-sub">'+rr.sub+(P.date?' · '+e(P.date):'')+'</div>':'')
    +'<div class="upu-body">'+rr.body+'</div>'
    +'<div class="upu-foot"><span class="upu-sent">◗ Sent from your phone</span></div>'
    +'</div></div>';
  host.innerHTML=html;
}
if(typeof document!=='undefined'){
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',render);else render();
}
if(typeof module!=='undefined')module.exports={parseSent:parseSent,render:render};
})();

</script>
